package com.example.myapp;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import java.util.List;

public class DeepLinkActivity extends AppCompatActivity {
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        Uri data = getIntent().getData();
        if (data != null) {
            List<String> segments = data.getPathSegments();
            if (!segments.isEmpty()) {
                switch (segments.get(0)) {
                    case "profile":
                        if (segments.size() > 1) {
                            String profileId = segments.get(1);
                            Intent profileIntent = new Intent(this, ProfileActivity.class);
                            profileIntent.putExtra("profileId", profileId);
                            startActivity(profileIntent);
                        }
                        break;
                    case "payment":
                        if (segments.size() > 1 && "confirm".equals(segments.get(1))) {
                            startActivity(new Intent(this, PaymentConfirmActivity.class));
                        }
                        break;
                    case "admin":
                        if (segments.size() > 1 && "settings".equals(segments.get(1))) {
                            startActivity(new Intent(this, AdminSettingsActivity.class));
                        }
                        break;
                }
            }
        }
        finish();
    }
}


